  ('bookkeeper-moex-00902', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '黃小姐106年度出租房地產，租期自106年1月1日至107年12月31日，出租時一次收取兩年期租金 80萬元，押金20萬元。假設未留存相關費用單據，郵政儲金一年期定期儲金固定利率為1%。請問黃小 姐106年度申報之租賃所得為多少元？', '["229,140元", "230,000元", "457,140元", "458,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
